import { useEffect, useState } from "react";
import axios from "axios";

function Notifications() {

  const user = JSON.parse(localStorage.getItem("user"));
  const [data, setData] = useState([]);

  useEffect(() => {
    axios.get(`http://localhost:5000/api/notifications/${user._id}`)
      .then(res => setData(res.data));
  }, []);

  return (
    <div className="main">
      <h2>🔔 Notifications</h2>

      {data.length === 0 ? (
        <p>No notifications</p>
      ) : (
        data.map(n => (
          <div key={n._id} className="card-box">

            <p>{n.message}</p>

            <button
              onClick={async () => {

                // ✅ mark as read
                await axios.put(
                  `http://localhost:5000/api/notifications/read/${n._id}`
                );

                // ✅ redirect
                if (n.type === "chat") {
                  window.location.href = `/chat/${n.appointmentId}`;
                } else {
                  window.location.href = "/appointments";
                }

              }}
            >
              {n.type === "chat"
                ? "Open Chat 💬"
                : "Open Appointment 📋"}
            </button>

          </div>
        ))
      )}
    </div>
  );
}

export default Notifications;
